classdef PaperStudySparseEvaluator
    %PAPERSTUDYSPARSEEVALUATOR Common unregularized P2 cost-curve harness.
    %
    % Every primary method receives the same rendered images, model camera,
    % pixels, labels, masks, and support. T4 alone consumes oracle surface
    % slope, and its invalid slope rows remain NaN. The frozen hybrid has zero
    % T3 weight and is therefore copied bit-exactly from ZNCC. Traceability:
    % algo/main.tex Secs. 6--8 and 10.1--10.4; Eqs. (79)--(84), (98),
    % (101), (103), (106)--(109), and (121)--(125); Algorithm 1.

    properties (SetAccess = private)
        Manifest (1, 1) struct
    end

    methods
        function obj = PaperStudySparseEvaluator(manifest)
            arguments
                manifest (1, 1) struct {mustBePaperStudyEvaluatorManifest}
            end
            obj.Manifest = manifest;
        end

        function result = evaluate(obj, rendered, options)
            %EVALUATE Run all twelve frozen primary methods at common points.
            arguments
                obj (1, 1) PaperStudySparseEvaluator
                rendered (1, 1) struct {mustBePaperStudyRenderedCase}
                options.DerivativeSigma (1, 1) double ...
                    {mustBeFinite, mustBePositive, ...
                    mustBeAllowedDerivativeSigma( ...
                    options.DerivativeSigma, obj)} = 1.2
                options.IntegrationSigma (1, 1) double ...
                    {mustBeFinite, mustBePositive, ...
                    mustBeAllowedIntegrationSigma( ...
                    options.IntegrationSigma, obj)} = 2
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBeNonnegative} = 1e-6
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.DeltaHeight (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
            end

            totalTimer = tic;
            use = rendered.TruthValid;
            p = rendered.SamplePixelXY(use, :);
            zt = rendered.TruthHeightMetres(use);
            wt = rendered.TruthCorrespondenceXY(use, :);
            td = rendered.TruthHeightDirectionXY(use, :);
            slope = rendered.TruthSurfaceSlopeMetresPerPixel(use, :);
            slopeValid = rendered.TruthJacobianValid(use) ...
                & all(isfinite(slope), 2);
            slope(~slopeValid, :) = 0;
            z = rendered.HeightLabelsMetres;
            minimumSupport = obj.Manifest.sceneContract. ...
                minimumSupportFraction;
            geom = HeightSweepGeometry(rendered.ReferenceCamera, ...
                rendered.MatchingMovingCamera);
            curve = HeightCostCurve(geom, rendered.ReferenceImage, ...
                rendered.MovingImage, ...
                DerivativeSigma=options.DerivativeSigma, ...
                IntegrationSigma=options.IntegrationSigma, ...
                ReferenceValid=rendered.ReferenceValid, ...
                MovingValid=rendered.MovingValid, ...
                WorkingPrecision=rendered.WorkingPrecision);

            baseTimer = tic;
            base = curve.evaluate(p, z, SurfaceSlope=slope, ...
                MinimumSupportFraction=minimumSupport, ...
                MinimumGradient=options.MinimumGradient, ...
                DeltaPixel=options.DeltaPixel, ...
                DeltaHeight=options.DeltaHeight, ...
                Channels=["Zncc", "Census", "NormalizedGradient", ...
                "PointSpin2", "Spin2T0", "Spin2T1", "Spin2T2", ...
                "Spin2T3", "Spin2T4"]);
            baseSeconds = toc(baseTimer);
            base.Costs.Spin2T4(~slopeValid, :) = NaN;
            base.Valid.Spin2T4(~slopeValid, :) = false;
            base.SupportFraction.Spin2T4(~slopeValid, :) = NaN;
            base.SelectedHeight.Spin2T4 = ...
                PaperStudySparseEvaluator.selectHeight( ...
                base.Costs.Spin2T4, z);

            gates = obj.factorGates(rendered);
            harmonicTimer = tic;
            harmonic = MultiHarmonicHeightCurve(curve).evaluate(p, z, ...
                DeltaPixel=options.DeltaPixel, ...
                MinimumSupportFraction=minimumSupport, ...
                MinimumGradient=options.MinimumGradient, ...
                FixedWeights=gates.FixedWeights, ...
                PolarityPreservedProbability= ...
                gates.PolarityPreservedProbability, ...
                OrthogonalStructureProbability= ...
                gates.OrthogonalStructureProbability, ...
                LowAngularNoiseProbability= ...
                gates.LowAngularNoiseProbability);
            harmonicSeconds = toc(harmonicTimer);

            primary = PaperStudySparseEvaluator.combine( ...
                p, z, base, harmonic, obj.Manifest.methods.primaryMatching);
            metrics = HeightCostMetrics.analyze(primary, zt);
            [metrics, summary] = PaperStudySparseEvaluator.endpointMetrics( ...
                metrics, primary, geom, p, wt, td, ...
                string(obj.Manifest.methods.oracleOnly));
            result = struct( ...
                "Identifier", rendered.Identifier, ...
                "MethodNames", ...
                string(obj.Manifest.methods.primaryMatching(:)).', ...
                "ReferencePointIndex", find(use), ...
                "ReferencePixel", p, ...
                "TruthHeightMetres", zt, ...
                "TruthCorrespondenceXY", wt, ...
                "HeightLabelsMetres", z, ...
                "PrimaryCurves", primary, ...
                "Metrics", metrics, ...
                "Summary", summary, ...
                "BaseCurve", base, ...
                "MultiHarmonicCurve", harmonic, ...
                "MultiHarmonicGates", gates, ...
                "T4OracleSlopeValid", slopeValid, ...
                "EvaluationSeconds", struct( ...
                "BaseChannels", baseSeconds, ...
                "MultiHarmonic", harmonicSeconds, ...
                "Total", toc(totalTimer)), ...
                "Regularization", "none", ...
                "CommonSupportFraction", minimumSupport, ...
                "PixelConvention", rendered.PixelConvention, ...
                "WorldFrame", rendered.WorldFrame, ...
                "ElevationDatum", rendered.ElevationDatum);
        end

        function result = evaluateDiagnostics(obj, rendered, options)
            %EVALUATEDIAGNOSTICS Run non-primary P2 residual diagnostics.
            arguments
                obj (1, 1) PaperStudySparseEvaluator
                rendered (1, 1) struct {mustBePaperStudyRenderedCase}
                options.DerivativeSigma (1, 1) double ...
                    {mustBeFinite, mustBePositive, ...
                    mustBeAllowedDerivativeSigma( ...
                    options.DerivativeSigma, obj)} = 1.2
                options.IntegrationSigma (1, 1) double ...
                    {mustBeFinite, mustBePositive, ...
                    mustBeAllowedIntegrationSigma( ...
                    options.IntegrationSigma, obj)} = 2
                options.MaximumConditionNumber (1, 1) double ...
                    {mustBeFinite, mustBePositive, ...
                    mustBeAllowedConditionNumber( ...
                    options.MaximumConditionNumber, obj)} = 10000
                options.GradientEnergyPercentile (1, 1) double ...
                    {mustBeFinite, ...
                    mustBeAllowedGradientPercentile( ...
                    options.GradientEnergyPercentile, obj)} = 10
                options.MinimumGradient (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 1e-6
                options.DeltaPixel (1, 1) double ...
                    {mustBeFinite, mustBePositive} = 0.5
                options.IncludeWidelyLinear (1, 1) logical = true
                options.IncludeComplexLog (1, 1) logical = true
            end

            totalTimer = tic;
            use = rendered.TruthValid;
            p = rendered.SamplePixelXY(use, :);
            zt = rendered.TruthHeightMetres(use);
            z = rendered.HeightLabelsMetres;
            support = obj.Manifest.sceneContract.minimumSupportFraction;
            geom = HeightSweepGeometry(rendered.ReferenceCamera, ...
                rendered.MatchingMovingCamera);
            base = HeightCostCurve(geom, rendered.ReferenceImage, ...
                rendered.MovingImage, ...
                DerivativeSigma=options.DerivativeSigma, ...
                IntegrationSigma=options.IntegrationSigma, ...
                ReferenceValid=rendered.ReferenceValid, ...
                MovingValid=rendered.MovingValid, ...
                WorkingPrecision=rendered.WorkingPrecision);

            wlResult = struct;
            wlSeconds = 0;
            if options.IncludeWidelyLinear
                timer = tic;
                wl = WidelyLinearHeightCurve(base).evaluate(p, z, ...
                    DeltaPixel=options.DeltaPixel, ...
                    MinimumSupportFraction=support, ...
                    MinimumGradient=options.MinimumGradient, ...
                    MaximumConditionNumber=options.MaximumConditionNumber);
                wlSeconds = toc(timer);
                wlResult = struct( ...
                    "Curve", wl, ...
                    "Metrics", HeightCostMetrics.analyze(wl, zt), ...
                    "TruthLabel", ...
                    PaperStudySparseEvaluator.widelyLinearTruth(wl, zt), ...
                    "MaximumConditionNumber", ...
                    options.MaximumConditionNumber);
            end

            logResult = struct;
            logSeconds = 0;
            if options.IncludeComplexLog
                timer = tic;
                logCurve = ComplexLogHeightCurve(base).evaluate(p, z, ...
                    DeltaPixel=options.DeltaPixel, ...
                    MinimumSupportFraction=support, ...
                    MinimumGradient=options.MinimumGradient, ...
                    GradientEnergyPercentile= ...
                    options.GradientEnergyPercentile);
                logSeconds = toc(timer);
                logResult = struct( ...
                    "Curve", logCurve, ...
                    "Metrics", HeightCostMetrics.analyze(logCurve, zt), ...
                    "GradientEnergyPercentile", ...
                    options.GradientEnergyPercentile);
            end
            result = struct( ...
                "Identifier", rendered.Identifier, ...
                "MethodNames", ...
                string(obj.Manifest.methods.diagnosticOnly(:)).', ...
                "ReferencePointIndex", find(use), ...
                "ReferencePixel", p, ...
                "TruthHeightMetres", zt, ...
                "HeightLabelsMetres", z, ...
                "WidelyLinearResidual", wlResult, ...
                "ComplexLogResidual", logResult, ...
                "AlongCrossTrackResidual", struct( ...
                "Definition", ...
                "reported per primary method by evaluate().Metrics", ...
                "HeightDirectionXY", ...
                rendered.TruthHeightDirectionXY(use, :)), ...
                "EvaluationSeconds", struct( ...
                "WidelyLinear", wlSeconds, ...
                "ComplexLog", logSeconds, ...
                "Total", toc(totalTimer)), ...
                "Role", "diagnostic-only; excluded from primary ranking", ...
                "NoPrimaryPromotion", true);
        end
    end

    methods (Access = private)
        function out = factorGates(obj, rendered)
            g = obj.Manifest.executionParameters.multiHarmonicGates;
            names = string(g.textureNames);
            k = find(names == string(rendered.Factors.Texture));
            if numel(k) ~= 1
                error("PaperStudySparseEvaluator:UnknownTextureGate", ...
                    "No frozen multi-harmonic gate exists for texture '%s'.", ...
                    string(rendered.Factors.Texture));
            end
            rad = string(rendered.Factors.Radiometry);
            if rad == "polarity-reversal"
                pol = g.polarityReversalPreservedProbability;
            else
                pol = g.otherRadiometryPreservedProbability;
            end
            quiet = g.lowAngularNoiseProbability(k);
            if rad == "noise"
                quiet = min(quiet, ...
                    g.noiseMaximumLowAngularNoiseProbability);
            end
            out = struct( ...
                "FixedWeights", reshape(g.fixedWeights, 1, []), ...
                "PolarityPreservedProbability", pol, ...
                "OrthogonalStructureProbability", ...
                g.orthogonalStructureProbability(k), ...
                "LowAngularNoiseProbability", quiet, ...
                "Source", string(g.definition));
        end
    end

    methods (Static, Access = private)
        function out = combine(p, z, base, harmonic, methodNames)
            methodNames = string(methodNames(:)).';
            source = struct( ...
                "Zncc", "Zncc", "Census", "Census", ...
                "NormalizedGradient", "NormalizedGradient", ...
                "Spin2Pointwise", "PointSpin2", ...
                "T0", "Spin2T0", "T1", "Spin2T1", ...
                "T2", "Spin2T2", "T3", "Spin2T3", ...
                "T4OracleSlope", "Spin2T4", ...
                "MultiHarmonicFixed", "Fixed124", ...
                "MultiHarmonicGated", "Adaptive124", ...
                "ZnccT3FrozenHybrid", "Zncc");
            costs = struct;
            selected = struct;
            valid = struct;
            support = struct;
            for method = methodNames
                name = char(method);
                src = char(source.(name));
                if startsWith(method, "MultiHarmonic")
                    c = harmonic.Costs.(src);
                    s = harmonic.SupportFraction.(src);
                else
                    c = base.Costs.(src);
                    if isfield(base.SupportFraction, src)
                        s = base.SupportFraction.(src);
                    else
                        s = nan(size(c));
                    end
                end
                costs.(name) = c;
                selected.(name) = ...
                    PaperStudySparseEvaluator.selectHeight(c, z);
                valid.(name) = isfinite(c);
                support.(name) = s;
            end
            out = struct( ...
                "ReferencePixel", p, "Height", z, ...
                "Costs", costs, "SelectedHeight", selected, ...
                "Valid", valid, "SupportFraction", support, ...
                "Regularization", "none", ...
                "Definition", ...
                "identical points, labels, masks, geometry, and support");
        end

        function [metrics, summary] = endpointMetrics( ...
                metrics, curves, geom, p, truth, direction, oracleNames)
            names = string(fieldnames(curves.Costs));
            n = size(p, 1);
            rows = cell(numel(names), 12);
            for k = 1:numel(names)
                name = char(names(k));
                m = metrics.(name);
                z = m.SelectedHeightMetres;
                w = nan(n, 2);
                projected = false(n, 1);
                q = isfinite(z);
                if any(q)
                    [w(q, :), projected(q)] = geom.warp(p(q, :), z(q));
                end
                r = w - truth;
                e = vecnorm(r, 2, 2);
                endpointValid = projected & all(isfinite(r), 2);
                e(~endpointValid) = NaN;
                dz = nan(n, 1);
                along = nan(n, 2);
                cross = nan(n, 2);
                residualValid = false(n, 1);
                if any(endpointValid)
                    [dz(endpointValid), along(endpointValid, :), ...
                        cross(endpointValid, :), ...
                        residualValid(endpointValid)] = ...
                        HeightSweepGeometry.decomposeResidual( ...
                        r(endpointValid, :), direction(endpointValid, :));
                end
                m.SelectedCorrespondenceXY = w;
                m.EndpointResidualXY = r;
                m.EndpointEpePixels = e;
                m.EndpointValid = endpointValid;
                m.EquivalentHeightResidualMetres = dz;
                m.AlongTrackResidualXY = along;
                m.CrossTrackResidualXY = cross;
                m.ResidualDecompositionValid = residualValid;
                metrics.(name) = m;
                h = m.SelectedHeightErrorMetres;
                rows(k, :) = {names(k), ismember(names(k), oracleNames), ...
                    n, mean(endpointValid), ...
                    PaperStudySparseEvaluator.rmsFinite(e), ...
                    PaperStudySparseEvaluator.percentile(e, 50), ...
                    PaperStudySparseEvaluator.percentile(e, 90), ...
                    PaperStudySparseEvaluator.percentile(e, 95), ...
                    mean(abs(h), "omitnan"), ...
                    PaperStudySparseEvaluator.rmsFinite(h), ...
                    mean(m.TruthCostPercentile, "omitnan"), ...
                    mean(m.IsUniqueTruthBest, "omitnan")};
            end
            summary = cell2table(rows, VariableNames=[ ...
                "Method", "OracleOnly", "SampleCount", ...
                "EndpointCoverage", "EndpointEpeRmsePixels", ...
                "EndpointEpeP50Pixels", "EndpointEpeP90Pixels", ...
                "EndpointEpeP95Pixels", "HeightMaeMetres", ...
                "HeightRmseMetres", "MeanTruthCostPercentile", ...
                "UniqueTruthBestFraction"]);
        end

        function out = widelyLinearTruth(curve, truthHeight)
            z = curve.Height;
            n = numel(truthHeight);
            [~, k] = min(abs(z - truthHeight), [], 2);
            ind = sub2ind([n, numel(z)], (1:n).', k);
            out = struct( ...
                "HeightMetres", reshape(z(k), [], 1), ...
                "A", curve.A(ind), "B", curve.B(ind), ...
                "Mu", curve.Mu(ind), ...
                "DeltaCost", curve.DeltaCost(ind), ...
                "ConditionNumber", curve.ConditionNumber(ind), ...
                "DesignRank", curve.DesignRank(ind), ...
                "FitValid", curve.FitValid(ind), ...
                "PhysicalValid", curve.PhysicalValid(ind));
        end

        function z = selectHeight(cost, labels)
            [~, k] = min(cost, [], 2, "omitnan");
            z = reshape(labels(k), [], 1);
            z(all(~isfinite(cost), 2)) = NaN;
        end

        function y = rmsFinite(x)
            y = sqrt(mean(x .^ 2, "omitnan"));
        end

        function y = percentile(x, q)
            x = sort(x(isfinite(x)));
            if isempty(x)
                y = NaN;
                return
            end
            k = 1 + (numel(x) - 1) .* q ./ 100;
            lo = floor(k);
            hi = ceil(k);
            y = x(lo) + (k - lo) .* (x(hi) - x(lo));
        end
    end
end

function mustBePaperStudyEvaluatorManifest(s)
required = ["sceneContract", "executionParameters", "tunablePolicy", ...
    "methods"];
if ~all(isfield(s, required)) ...
        || ~isfield(s.executionParameters, "multiHarmonicGates")
    error("PaperStudySparseEvaluator:InvalidManifest", ...
        "The P2 manifest lacks sparse-evaluation policy fields.");
end
end

function mustBePaperStudyRenderedCase(s)
required = ["Identifier", "Factors", "ReferenceImage", "MovingImage", ...
    "ReferenceValid", "MovingValid", "ReferenceCamera", ...
    "MatchingMovingCamera", "SamplePixelXY", "TruthHeightMetres", ...
    "TruthCorrespondenceXY", "TruthValid", ...
    "TruthHeightDirectionXY", "TruthSurfaceSlopeMetresPerPixel", ...
    "TruthJacobianValid", "HeightLabelsMetres", "WorkingPrecision", ...
    "PixelConvention", "WorldFrame", "ElevationDatum"];
if ~all(isfield(s, required))
    error("PaperStudySparseEvaluator:InvalidRenderedCase", ...
        "Input must be a complete PaperStudySyntheticCase render result.");
end
end

function mustBeAllowedDerivativeSigma(x, obj)
if ~ismember(x, obj.Manifest.tunablePolicy.derivativeSigmaPixels)
    error("PaperStudySparseEvaluator:UnregisteredDerivativeSigma", ...
        "DerivativeSigma must be one of the preregistered values.");
end
end

function mustBeAllowedIntegrationSigma(x, obj)
if ~ismember(x, obj.Manifest.tunablePolicy.integrationSigmaPixels)
    error("PaperStudySparseEvaluator:UnregisteredIntegrationSigma", ...
        "IntegrationSigma must be one of the preregistered values.");
end
end

function mustBeAllowedConditionNumber(x, obj)
if ~ismember(x, obj.Manifest.tunablePolicy.widelyLinearConditionLimit)
    error("PaperStudySparseEvaluator:UnregisteredConditionNumber", ...
        "MaximumConditionNumber must be preregistered.");
end
end

function mustBeAllowedGradientPercentile(x, obj)
if ~ismember(x, ...
        obj.Manifest.tunablePolicy.complexLogGradientEnergyPercentile)
    error("PaperStudySparseEvaluator:UnregisteredGradientPercentile", ...
        "GradientEnergyPercentile must be preregistered.");
end
end
